const { Storage } = require('@google-cloud/storage');
const storage = new Storage();
const path = require('path');

const ALLOWED_BUCKETS = process.env.ALLOWED_BUCKETS ? process.env.ALLOWED_BUCKETS.split(',') : [];
const MAX_FILE_SIZE = parseInt(process.env.MAX_FILE_SIZE) || 50 * 1024 * 1024; // 50MB

exports.serveFile = async (req, res) => {
  // Set CORS headers
  res.set('Access-Control-Allow-Origin', '*');
  res.set('Access-Control-Allow-Methods', 'GET, OPTIONS');
  res.set('Access-Control-Allow-Headers', 'Content-Type');

  if (req.method === 'OPTIONS') {
    res.status(204).send('');
    return;
  }

  try {
    // Validate bucket parameter
    const bucketName = req.query.bucket;
    if (!bucketName || !ALLOWED_BUCKETS.includes(bucketName)) {
      return res.status(403).send('Forbidden');
    }

    // Validate file path parameter
    const filePath = req.query.path;
    if (!filePath) {
      return res.status(400).send('Bad Request: path parameter required');
    }

    // Sanitize file path to prevent directory traversal
    const sanitizedPath = path.normalize(filePath).replace(/^(\.\.[\/\\])+/, '');
    if (sanitizedPath.startsWith('..')) {
      return res.status(400).send('Bad Request: Invalid path');
    }

    // Validate file path length
    if (sanitizedPath.length > 1024) {
      return res.status(400).send('Bad Request: Path too long');
    }

    const bucket = storage.bucket(bucketName);
    const file = bucket.file(sanitizedPath);

    // Check if file exists
    const [exists] = await file.exists();
    if (!exists) {
      return res.status(404).send('File not found');
    }

    // Get file metadata
    const [metadata] = await file.getMetadata();
    
    // Validate file size
    if (metadata.size > MAX_FILE_SIZE) {
      return res.status(400).send('File too large');
    }

    // Set appropriate headers
    res.set('Content-Type', metadata.contentType || 'application/octet-stream');
    res.set('Content-Length', metadata.size);
    
    // Set cache headers
    res.set('Cache-Control', 'public, max-age=3600');
    
    // Stream file
    const fileStream = file.createReadStream();
    fileStream.on('error', (err) => {
      console.error('Error streaming file:', err);
      res.status(500).send('Internal Server Error');
    });
    
    fileStream.pipe(res);
    
  } catch (error) {
    console.error('Error serving file:', error);
    res.status(500).send('Internal Server Error');
  }
};